import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.CxzqQz9c.js";const u=JSON.parse('{"title":"技术写作","description":"","frontmatter":{},"headers":[],"relativePath":"technical-writing.md","filePath":"technical-writing.md"}'),i={name:"technical-writing.md"};function l(d,t,c,n,h,s){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="技术写作" tabindex="-1">技术写作 <a class="header-anchor" href="#技术写作" aria-label="Permalink to &quot;技术写作&quot;">​</a></h1><blockquote><p>技术写作不是把话说得「高级」,而是把复杂的事情说得<strong>准确、可执行、可复现</strong>。 这一节记录我在 B2B 工业领域做技术内容时总结的写作规范与工程纪律。</p></blockquote><hr><h2 id="写作哲学" tabindex="-1">写作哲学 <a class="header-anchor" href="#写作哲学" aria-label="Permalink to &quot;写作哲学&quot;">​</a></h2><p>好的技术内容,应该满足三条标准:</p><ol><li><strong>Accurate(准确)</strong>——每一个参数、命令、路径都必须经过实测,不留模糊</li><li><strong>Actionable(可执行)</strong>——读者照着做,能直接跑通,而不是「自行研究」</li><li><strong>Reproducible(可复现)</strong>——同样的输入,产出同样的结果,可审计、可回溯</li></ol><hr><h2 id="b2b-工业内容的特殊性" tabindex="-1">B2B 工业内容的特殊性 <a class="header-anchor" href="#b2b-工业内容的特殊性" aria-label="Permalink to &quot;B2B 工业内容的特殊性&quot;">​</a></h2><p>面向消费市场的 SEO 文案,追求的是情绪共鸣和点击率。 而 B2B 工业采购决策者完全不同——他们是工程师、是采购主管,要的是<strong>规格、参数、合规性</strong>。</p><p>因此写作时必须遵守以下纪律:</p><table tabindex="0"><thead><tr><th>维度</th><th>消费市场写法</th><th>B2B 工业写法</th></tr></thead><tbody><tr><td>标题</td><td>情绪化、悬念式</td><td><code>12V Electric Jacks Capacity | Henghong</code></td></tr><tr><td>正文</td><td>故事、场景</td><td>Spec table, compliance, drawing</td></tr><tr><td>CTA</td><td>&quot;立即抢购&quot;</td><td>&quot;Request a datasheet / RFQ&quot;</td></tr><tr><td>关键词</td><td>短尾、高搜索量</td><td>长尾、高意图,如 <code>hydraulic cylinder supplier ISO 9001</code></td></tr></tbody></table><hr><h2 id="待补充章节" tabindex="-1">待补充章节 <a class="header-anchor" href="#待补充章节" aria-label="Permalink to &quot;待补充章节&quot;">​</a></h2><p>这一节还在持续构建中,后续会加入:</p><ul><li>Title / Description 的标准化模板</li><li>产品规格表(Spec Table)的 Markdown 范式</li><li>Schema.org 结构化数据的嵌入规范</li><li>面向 GEO 的 <code>llms.txt</code> 生成策略</li></ul><hr><blockquote><p>内容持续迭代中,欢迎回到首页查看最新更新。</p></blockquote>',17)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
